import java.util.concurrent.TimeUnit

object NetworkModule {

    private const val BASE_URL_DEV = "https://api.dev.example.com/"
    private const val BASE_URL_STAGING = "https://api.staging.example.com/"
    private const val BASE_URL_PRODUCTION = "https://api.example.com/"

    private const val ENVIRONMENT = "DEV" // Change to "STAGING" or "PRODUCTION" as needed

    private val baseUrl: String = when (ENVIRONMENT) {
        "DEV" -> BASE_URL_DEV
        "STAGING" -> BASE_URL_STAGING
        "PRODUCTION" -> BASE_URL_PRODUCTION
        else -> BASE_URL_PRODUCTION
    }

    private fun provideOkHttpClient(authToken: String?): OkHttpClient {
        val logging = HttpLoggingInterceptor()
        logging.setLevel(HttpLoggingInterceptor.Level.BODY)

        val interceptor = Interceptor { chain ->
            val original = chain.request()
            val requestBuilder = original.newBuilder()
                .apply {
                    if (!authToken.isNullOrEmpty()) {
                        header("Authorization", "Bearer $authToken")
                    }
                }
            val request = requestBuilder.build()
            chain.proceed(request)
        }

        return OkHttpClient.Builder()
            .addInterceptor(logging)
            .addInterceptor(interceptor)
            .callTimeout(30, TimeUnit.SECONDS)
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()
    }

    private val retrofit: Retrofit by lazy {
        Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(provideOkHttpClient(null))  // Replace 'null' with token when available
